var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"아직…","JPN":"まだ……","ENG":"Not yet…","TWN":"還…"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…끝나지 않았어.","JPN":"……終わっていない。","ENG":"…It's not over.","TWN":"…沒結束。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"대답이 틀려.","JPN":"話が違うわ。","ENG":"Wrong answer.","TWN":"答案不對。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"지면 순순히 물러나기로 합의했잖아?","JPN":"負けたら素直に引き下がるって約束だったでしょう？","ENG":"We agreed you'd back down if you lost.","TWN":"我們不是說好，如果你輸了就乖乖回去嗎？"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그래도 마지막은 매섭더라. 정말 목숨을 건 싸움이었다면 나도 상처를 입었겠지.","JPN":"でも最後はなかなかだったわ。これが本当に命をかけた戦いだったら、私も傷を負っていたでしょう。","ENG":"Still, that last move packed a punch. If we were really fighting to the death, I might've gotten hurt.","TWN":"不過你最後的攻勢很凌厲。如果是一場真正的生死戰，我也會受傷吧。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신을 너무 얕봤다는 건 인정할게.","JPN":"あなたを見くびっていたことは認めるわ。","ENG":"I'll admit, I underestimated you.","TWN":"我承認我太小看你了。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"왜 그렇게까지… 내 도움을 거부하는 거요?","JPN":"なぜそこまで……某の助けを拒む？","ENG":"Then why are you… so determined to keep me out of this?","TWN":"你為什麼要…如此拒絕我的幫助？"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"고작 짐승 하날 잡으려고, 우리 모두가 희생할 필요는 없으니까.","JPN":"たかがケモノ1匹ごときのために、私たち全員が犠牲になる必要はないからよ。","ENG":"Because there's no need to sacrifice all of us just to take down one Beast.","TWN":"因為為了抓一隻野獸，沒有必要讓我們所有人都犧牲。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"희생이라니?","JPN":"犠牲？","ENG":"Sacrifice?","TWN":"犧牲？"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SURPRISE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"함께 싸우고 함께 사는 거요. 누구도 희생할 필요 없이.","JPN":"共に戦い、共に生きるのだ。誰も犠牲にならずに。","ENG":"No one's sacrificing anyone. We fight together, we survive together.","TWN":"我們一起戰鬥，一起活著。沒有人需要犧牲。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>기슭의 짐승</color>은 맞서 싸우는 존재가 아니야.","JPN":"<color=#ffd34c>麓のケモノ</color>は真向から戦う相手じゃないわ。","ENG":"<color=#ffd34c>The Ridge Beast</color> isn't something you fight head-on.","TWN":"<color=#ffd34c>山腳下的野獸</color>不是能戰勝的存在。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"녀석이 현실로 침범하는 걸 막으려면, 돌아올 수 없을 만큼 깊은 곳으로 떨어트리는 수밖에 없어.","JPN":"やつが現実に侵入するのを防ぐためには、戻って来れないほど深いところに落とすしかない。","ENG":"The only way to stop it from breaking into reality… is to drag it down so deep it can't ever crawl back out.","TWN":"為了阻止牠入侵現實，只能將牠推到一個無法返回的深淵。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그 작전이 성공하려면 누군가는 그 짐승을 붙잡고 있어야만 해.","JPN":"そして、その作戦を成功させるためには、誰かがやつを捕まえておく必要があるわ。","ENG":"And to make that happen, someone has to hold the Beast down.","TWN":"要讓那個作戰成功，就必須有人抓住那隻野獸。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"다신 이 땅에 기어오르지 못하도록, 함께 나락의 끝까지 떨어지는 거지.","JPN":"二度とこの地に這い上がって来れないように、共に奈落の底まで落ちるのよ。","ENG":"All the way to the bottom, so it can never resurface.","TWN":"和牠一起墜入地獄的深處，讓牠再也無法爬回這片土地。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그렇게 하면 그대는 살아 돌아오지 못할 거요!","JPN":"そうするとそなたは生きて帰れない！","ENG":"If you do that, you won't make it back!","TWN":"那樣的話，你將無法活著回來！"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"괜찮아.","JPN":"大丈夫よ。","ENG":"It's fine.","TWN":"沒關係。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"각오는 충분히 했으니까.","JPN":"覚悟は十分できているわ。","ENG":"I've already made peace with that.","TWN":"我已經做好了充分的覺悟。"},"stage":{"bg":"REEDS_FIELD_02","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"연화, 서둘러야겠구나.","JPN":"レンカ、急ごう。","ENG":"Yeonhwa, you need to hurry.","TWN":"蓮華，要加快了。"},"stage":{"bg":"SKY_BLACK","slots":{"L":null,"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"범오름의 전조다.","JPN":"虎来の前兆が見えてきた。","ENG":"It's the omen of the Tiger's Ascent.","TWN":"這是老虎即將出現的徵兆。"},"stage":{"bg":"SKY_BLACK","slots":{"L":null,"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…전조라고?","JPN":"……前兆ですって？","ENG":"…Omen?","TWN":"…徵兆？"},"stage":{"bg":"SKY_BLACK","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"아직 시간은 충분할 텐데… 어째서?","JPN":"まだ時間に余裕があるはず……どうして？","ENG":"But there should still be time… Why now?","TWN":"時間應該還很充足才對…為什麼？"},"stage":{"bg":"SKY_BLACK","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"하늘뿐만 아니라 땅까지 검게 물들고 있군.","JPN":"空だけでなく地面まで黒く染まっている。","ENG":"Not just the sky, look at the ground. It's going dark too.","TWN":"不只天空，連大地都被染成黑色了。"},"stage":{"bg":"SKY_BLACK","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};